// // This module selects between two inputs based on the selection signal.
// If Sel is 0, Out will be equal to B; if Sel is 1, Out will be equal to A.
module mux_2to1 (
    input A,
    input B,
    input Sel,
    output Out,
    input VPB,
    input VPWR,
    input VGND,
    input VNB
);

assign Out = (!Sel & A) | (Sel & B);

endmodule
